import{i as a,o as n,a as s,q as t,x as p,u as e,e as o,s as c,p as l,c as u,b as i,r,l as k,h as d,w as g,f as h,m,F as v,j as f,t as b}from"./app.a6be710e.js";const w=["value"],_={props:{value:{required:!0}},setup(l){const u=a("radioModel");return(a,i)=>(n(),s("div",null,[t(o("input",{type:"radio","onUpdate:modelValue":i[0]||(i[0]=a=>c(u)?u.value=a:null),value:l.value},null,8,w),[[p,e(u)]])]))}},y={props:{modelValue:{required:!0}},emits:["update:modelValue"],setup(a,{emit:t}){const p=a;return l("radioModel",u({get:()=>p.modelValue,set(a){t("update:modelValue",a)}})),(a,t)=>(n(),s("div",null,[i(a.$slots,"default")]))}},q=m('<h1 id="radio-group" tabindex="-1">Radio Group <a class="header-anchor" href="#radio-group" aria-hidden="true">#</a></h1><h2 id="radio-group-example" tabindex="-1">Radio Group Example <a class="header-anchor" href="#radio-group-example" aria-hidden="true">#</a></h2><p>A radio group component acts as a wrapper around multiple radio components, with a single <code>v-model</code> on the wrapper:</p><div class="language-vue"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>basic-radio-group</span> <span class="token attr-name">v-model</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>radioValue<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>basic-radio</span> <span class="token attr-name">value</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>First<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>basic-radio</span> <span class="token attr-name">value</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>Second<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>basic-radio</span> <span class="token attr-name">value</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>Third<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>basic-radio-group</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>pre</span><span class="token punctuation">&gt;</span></span>Bound value: {{ radioValue }}<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>pre</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>\n\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span> <span class="token attr-name">setup</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">\n<span class="token keyword">import</span> <span class="token punctuation">{</span> ref <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;vue&#39;</span>\n<span class="token keyword">import</span> BasicRadio <span class="token keyword">from</span> <span class="token string">&#39;./radio.vue&#39;</span>\n<span class="token keyword">import</span> BasicRadioGroup <span class="token keyword">from</span> <span class="token string">&#39;./radio-group.vue&#39;</span>\n\n<span class="token keyword">const</span> radioValue <span class="token operator">=</span> <span class="token function">ref</span><span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span>\n</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>\n</code></pre></div><p>It would look something like this:</p>',5),V=m('<p><code>radio-group.vue</code> would use <code>provide</code> to communicate with <code>radio.vue</code>:</p><div class="language-vue"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>slot</span> <span class="token punctuation">/&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>\n\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span> <span class="token attr-name">setup</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">\n<span class="token keyword">import</span> <span class="token punctuation">{</span> computed<span class="token punctuation">,</span> provide <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;vue&#39;</span>\n\n<span class="token keyword">const</span> props <span class="token operator">=</span> <span class="token function">defineProps</span><span class="token punctuation">(</span><span class="token punctuation">{</span>\n  modelValue<span class="token operator">:</span> <span class="token punctuation">{</span>\n    required<span class="token operator">:</span> <span class="token boolean">true</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span>\n\n<span class="token keyword">const</span> emit <span class="token operator">=</span> <span class="token function">defineEmits</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token string">&#39;update:modelValue&#39;</span><span class="token punctuation">]</span><span class="token punctuation">)</span>\n\n<span class="token function">provide</span><span class="token punctuation">(</span><span class="token string">&#39;radioModel&#39;</span><span class="token punctuation">,</span> <span class="token function">computed</span><span class="token punctuation">(</span><span class="token punctuation">{</span>\n  <span class="token function">get</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token keyword">return</span> props<span class="token punctuation">.</span>modelValue\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  <span class="token function">set</span> <span class="token punctuation">(</span>value<span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token function">emit</span><span class="token punctuation">(</span><span class="token string">&#39;update:modelValue&#39;</span><span class="token punctuation">,</span> value<span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\n</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span></code></pre></div><p>The <code>radio.vue</code> here is specially written to use <code>inject</code> instead of a <code>modelValue</code>:</p><div class="language-vue"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">type</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>radio<span class="token punctuation">&quot;</span></span> <span class="token attr-name">v-model</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>radioModel<span class="token punctuation">&quot;</span></span> <span class="token attr-name">:value</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>value<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>\n\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span> <span class="token attr-name">setup</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">\n<span class="token keyword">import</span> <span class="token punctuation">{</span> inject <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;vue&#39;</span>\n\n<span class="token keyword">const</span> props <span class="token operator">=</span> <span class="token function">defineProps</span><span class="token punctuation">(</span><span class="token punctuation">{</span>\n  value<span class="token operator">:</span> <span class="token punctuation">{</span>\n    required<span class="token operator">:</span> <span class="token boolean">true</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span>\n\n<span class="token keyword">const</span> radioModel <span class="token operator">=</span> <span class="token function">inject</span><span class="token punctuation">(</span><span class="token string">&#39;radioModel&#39;</span><span class="token punctuation">)</span>\n</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span></code></pre></div><p>Support for direct use of <code>v-model</code> with the <code>radio</code> component has been omitted from this example. That technique is shown in the <a href="./radio.html">Radio example</a>. The two can be combined by using a default value with <code>inject</code> and then checking whether that value is set.</p><h2 id="vue-patterns" tabindex="-1">Vue Patterns <a class="header-anchor" href="#vue-patterns" aria-hidden="true">#</a></h2><p>See <a href="./../patterns/coupled-components-with-provide-inject.html">Coupled Components with <code>provide</code>/<code>inject</code></a></p><p>Apart from the naming choices, there&#39;s nothing in this <code>radio-group.vue</code> implementation that assumes the children are radio buttons. It could be made to work with checkboxes, toggle switches or any similar components that involve picking from a list of options.</p><p>It could be argued that injecting a <code>computed</code> like this is violating one-way data flow for updates, or at least it gives that impression from the perspective of <code>radio.vue</code>. You could inject a separate <code>ref</code> and update function if you prefer.</p>',9),T=m('<h2 id="alternatives" tabindex="-1">Alternatives <a class="header-anchor" href="#alternatives" aria-hidden="true">#</a></h2><p>Another way to implement a radio group would be to use a prop to pass the options rather than a slot. e.g.:</p><div class="language-vue"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>basic-radio-group</span>\n    <span class="token attr-name">v-model</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>radioValue<span class="token punctuation">&quot;</span></span>\n    <span class="token attr-name">:options</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>[<span class="token punctuation">&#39;</span>First<span class="token punctuation">&#39;</span>, <span class="token punctuation">&#39;</span>Second<span class="token punctuation">&#39;</span>, <span class="token punctuation">&#39;</span>Third<span class="token punctuation">&#39;</span>]<span class="token punctuation">&quot;</span></span>\n  <span class="token punctuation">/&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>\n</code></pre></div><p>As the radio group is now responsible for creating the child components, it can use props and events for communicating with the children rather than <code>provide</code>/<code>inject</code>. This does simplify the implementation of the children, but it also forces the radio group to take on responsibility for laying out the radios. Whereas a slot allows other containers, dividers and text to be included along with the radios, the prop-based approach needs everything to be passed in via props. The slot-based approach could be seen as a better separation of concerns, though if you don&#39;t need the extra flexibility it may be unnecessary complexity.</p><p>Both approaches could be implemented in the same component.</p><h2 id="libraries" tabindex="-1">Libraries <a class="header-anchor" href="#libraries" aria-hidden="true">#</a></h2><p>Various libraries include a radio component, including:</p><ul><li>Ant Design Vue - <a href="https://2x.antdv.com/components/radio" target="_blank" rel="noopener noreferrer">Radio Group</a></li><li>Element Plus - <a href="https://element-plus.org/en-US/component/radio.html" target="_blank" rel="noopener noreferrer">Radio Group</a></li><li>Quasar - <a href="https://quasar.dev/vue-components/option-group" target="_blank" rel="noopener noreferrer">Option Group</a> (uses a prop-based approach for the options)</li><li>Headless UI - <a href="https://headlessui.dev/vue/radio-group" target="_blank" rel="noopener noreferrer">Radio Group</a></li><li>Naive UI - <a href="https://www.naiveui.com/en-US/os-theme/components/radio" target="_blank" rel="noopener noreferrer">Radio Group</a>\x3c!-- - PrimeVue - [RadioButton](https://primefaces.org/primevue/showcase/#/radiobutton) --\x3e</li></ul>',8),x='{"title":"Radio Group","description":"","frontmatter":{"sidebarDepth":4},"headers":[{"level":2,"title":"Radio Group Example","slug":"radio-group-example"},{"level":2,"title":"Vue Patterns","slug":"vue-patterns"},{"level":2,"title":"Alternatives","slug":"alternatives"},{"level":2,"title":"Libraries","slug":"libraries"}],"relativePath":"components/radio-group.md","lastUpdated":1642123854198}',A={};const R=Object.assign(A,{setup:function(a){const t=r("First"),p=["First","Second","Third"];return(a,e)=>{const c=k("live-example");return n(),s("div",null,[q,d(c,null,{default:g((()=>[h(" template tag to keep VitePress from mangling everything "),t.value?(n(),s(v,{key:0},[d(y,{modelValue:t.value,"onUpdate:modelValue":e[0]||(e[0]=a=>t.value=a)},{default:g((()=>[(n(),s(v,null,f(p,(a=>d(_,{value:a},null,8,["value"]))),64))])),_:1},8,["modelValue"]),o("pre",null,"Bound value: "+b(t.value),1)],64)):h("v-if",!0)])),_:1}),V,h("\n## Missing Functionality\n\n## Related Components\n"),T])}}});export{x as __pageData,R as default};
